mapper.select:
SELECT * FROM service_task
WHERE level = #{level}

    AND status = #{status}

ORDER BY created_at DESC

mapper.update:
UPDATE service_task
SET status     = #{status},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE service_task
SET status      = 'Processing',
    assigned_to = #{assignedTo},
    updated_at  = #{updatedAt}
WHERE id = #{id}

UPDATE service_task
SET status     = 'Escalated',
    level      = 2,
    assigned_to= NULL,
    updated_at = #{updatedAt}
WHERE id = #{id}
